const Q_AGRICULTURE_2013=[{"id": "objective>Agriculture>2013>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which subject is given to you?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Agriculture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Biology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chemistry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Physics</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The question explicitly asks 'Which subject is given to you?' and the subject given in the question id is 'Agriculture'. Therefore, the correct answer is 'Agriculture'.</div>", "topic": "MEANING AND SCOPE OF AGRICULTURE"}, {"id": "objective>Agriculture>2013>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major reason which necessitates the expansion of agriculture is the increase in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rainfalls</div>", "<div style=\"font-family:Cambria;font-size:17px;\">population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">manpower</div>", "<div style=\"font-family:Cambria;font-size:17px;\">animal power</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The exponential increase in human and animal population necessitates the need for an expansion in the area of Agriculture. This is important in order to increase food production and meet other necessary needs of the society.</div>", "topic": "IMPORTANCE OF AGRICULTURE"}, {"id": "objective>Agriculture>2013>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following groups of crops are mostly cultivated in the rainforest zone of Nigeria?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Millet, yam and coconut</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Maize, cocoyam and cassava</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sorghum, sweet potato and date</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Wheat, Irish potato and groundnut</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Maize, cocoyam and cassava are crops mostly propagated in the rain forest zones, because the climatic characteristics of these zones favours the growth of these crops.</div>", "topic": "CROP HUSBANDRY : TUBERS"}, {"id": "objective>Agriculture>2013>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In farm animals, gonads are organs associated with</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">circulation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excretion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">respiration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reproduction</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gonads are the primary reproductive organs of an animal. They produce gametes (sex cells) and secrete hormones, which are necessary for reproduction. Therefore, they are associated with reproduction, not circulation, excretion, or respiration.</div>", "topic": "ANATOMY AND PHYSIOLOGY OF FARM ANIMALS : FUNCTIONS OF TISSUES AND ORGANS OF FARM ANIMALS"}, {"id": "objective>Agriculture>2013>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following combinations of farm inputs enhances the healthy growth of crop?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tractor and cash</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Irrigation and fertilizer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Work bull and implement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cutlass and sacks</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Irrigation and fertilizer best enhance the proper growth of plants. Irrigation is essential for the supply of water while fertilizer application is essential for adequate nutrient supply.</div>", "topic": "CROP HUSBANDRY : FERTILIZER"}, {"id": "objective>Agriculture>2013>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When farmers engages in both plant and animal husbandry, he is practising</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lay farming</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mixed framing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mixed cropping</div>", "<div style=\"font-family:Cambria;font-size:17px;\">crop rotation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mixed farming is the effective combination of crop cultivation and animal husbandry on the same portion of land.</div>", "topic": "CROP HUSBANDRY : MIXED FARMING"}, {"id": "objective>Agriculture>2013>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The classification of soils into sand, loam and clay is largely determine by the percentage of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mineral matter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">organic matter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">soil water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">soil air</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The discrepancies in the percentages of mineral matter in these soil types forms the basis of their classification.</div>", "topic": "ROCKS AND SOIL FORMATION"}, {"id": "objective>Agriculture>2013>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of igneous rock is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">marble</div>", "<div style=\"font-family:Cambria;font-size:17px;\">basalt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">slate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dolomite</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Basalt is a mafic extrusive igneous rock formed from the rapid cooling of magnesium-rich and Iron-rich larva exposed at or very near the surface of the moon. Basalt forms 90% of the igneous rock that we have on earth.</div>", "topic": "ROCKS AND SOIL FORMATION"}, {"id": "objective>Agriculture>2013>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most devastating agent of erosion is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wild wind</div>", "<div style=\"font-family:Cambria;font-size:17px;\">slope</div>", "<div style=\"font-family:Cambria;font-size:17px;\">run-off water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rodents</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Run-off water is the most devastating cause of soil erosion. It washes away the top soil and adversely affecting the structure of the soil.</div>", "topic": "ENVIRONMENTAL FACTORS"}, {"id": "objective>Agriculture>2013>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A farming practice that encourages the depletion of soil fertility is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">planting of cover crops</div>", "<div style=\"font-family:Cambria;font-size:17px;\">crop rotation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">manual weeding</div>", "<div style=\"font-family:Cambria;font-size:17px;\">continuous cropping</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Continuous cropping leads to a depletion in the percentage of useful nutrients in the soil. When a farmer notices that the soil he is working on is nutrient-depleted as a result of continuous cropping, what he resorts to is bush fallowing.</div>", "topic": "CROP HUSBANDRY"}, {"id": "objective>Agriculture>2013>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The kind of tillage method most suitable for maize is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">zero tillage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">minimum tillage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">maximum tillage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contour ridges</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Maximum tillage is the most suitable method for maize. This is because maize requires a well-prepared seedbed for optimal growth. Maximum tillage involves the use of heavy machinery to completely turn and break up the soil, which helps in the control of weeds and pests, and also improves the soil structure and nutrient availability for the maize crop. The other options like zero tillage, minimum tillage, and contour ridges are not as suitable for maize as they do not provide the same level of soil preparation.</div>", "topic": "LAND PREPARATION AND SOIL TILLAGE"}, {"id": "objective>Agriculture>2013>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this questions. <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The structure labeled I represents a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">root tuber</div>", "<div style=\"font-family:Cambria;font-size:17px;\">groundnut</div>", "<div style=\"font-family:Cambria;font-size:17px;\">root nodule</div>", "<div style=\"font-family:Cambria;font-size:17px;\">root hair</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The structure labelled I in the diagram is the root hair.</div>", "topic": "PLANT FORMS AND FUNCTIONS"}, {"id": "objective>Agriculture>2013>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this questions. <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> This type of root is associated with</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nitrogen fixation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">photosynthesis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">storage of organic acids</div>", "<div style=\"font-family:Cambria;font-size:17px;\">storage of minerals</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The dark portion in the diagram are root nodules. Note that bacteria like nitrosomonas help in nitrogen fixation.</div>", "topic": "PLANT FORMS AND FUNCTIONS : MONOCOT AND DICOT CROP PLANTS"}, {"id": "objective>Agriculture>2013>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Self-pollination takes place when grains are transferred from the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">stigma to the anther of another plant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stigma to the anther of same plant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">anther to the stigma of same plant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">anther to the stigma of another plant.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pollination is a reproductive process in plants which involves the transfer of pollen grains from anther to stigma. Note that self-pollination occurs when pollination takes place within a plant,i.e, there is a transfer of pollen grains from anther to the stigma of the same plant.</div>", "topic": "PLANT PROPAGATION METHODS : SEXUAL"}, {"id": "objective>Agriculture>2013>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following parts of plants are normally used for vegetative propagation?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Fruit, leaf and root.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Stem, root and leaf.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fruit, leaf and flower.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Leaf, flower and stem.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Vegetative propagation literally means asexual reproduction. In plants, the materials for asexual reproductive are the vegetative parts of the plant, these parts include the roots, stems, leaves. Note that fruit is associated with the reproductive (sexual) part of a plant.</div>", "topic": "PLANT PROPAGATION METHODS"}, {"id": "objective>Agriculture>2013>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most suitable planting pattern for a mechanized farm which is mono cropped is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">band placement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">drilling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">top dressing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">side dressing</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a mechanized farm that is mono cropped, the most suitable planting pattern is drilling. Drilling is a method of sowing seeds in rows rather than scattering them over a wide area. This method is more efficient and allows for better control over the depth at which seeds are planted. </div>", "topic": "CROPPING SYSTEMS, PLANTING PATTERNS AND PLANT DENSITIES"}, {"id": "objective>Agriculture>2013>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Jute and kenaf thrive well in a soil that is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">clayey</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sandy loam</div>", "<div style=\"font-family:Cambria;font-size:17px;\">clayey loam</div>", "<div style=\"font-family:Cambria;font-size:17px;\">humus</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Jute and kenaf are both plants that are used for their strong fibers. These plants thrive well in a soil that is clayey loam. Clayey loam is a type of soil that has a good balance of clay, silt, and sand. It has good water retention and nutrient holding capacity, which makes it suitable for growing these types of plants. </div>", "topic": "CROP HUSBANDRY : FIBRES"}, {"id": "objective>Agriculture>2013>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Forages that are chopped green and fed directly to livestock are referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hay</div>", "<div style=\"font-family:Cambria;font-size:17px;\">silage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fodder</div>", "<div style=\"font-family:Cambria;font-size:17px;\">soilage</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fodder refers to food, especially dried hay or straw, for cattle and other livestock. It is often used to refer to food given to animals rather than the food they forage for themselves. In this context, forages that are chopped green and fed directly to livestock are referred to as fodder.</div>", "topic": "CROP HUSBANDRY : FODDER CROPS"}, {"id": "objective>Agriculture>2013>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Floriculture deals with the study of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">flowers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fossils</div>", "<div style=\"font-family:Cambria;font-size:17px;\">weeds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">insects</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Floriculture, or flower farming, is a discipline of horticulture concerned with the cultivation of flowering and ornamental plants for gardens and for floristry, comprising the floral industry. The development, via plant breeding, of new varieties is a major occupation of floriculturists.</div>", "topic": "FLORICULTURE"}, {"id": "objective>Agriculture>2013>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An advantage of weeds is that they are used to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">control insect pest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">check grazing by animals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">check erosion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">control diseases</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Weeds can be beneficial in a number of ways. One of the advantages of weeds is that they can be used to check erosion. Weeds, especially those with extensive root systems, can help hold the soil together and prevent it from being washed away by rain or blown away by wind.</div>", "topic": "WEEDS"}, {"id": "objective>Agriculture>2013>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Cassava mosaic disease is transmitted by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"font-style:italic;\"> Heteroligus meles </span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"font-style:italic;\"> Maruca testulalis </span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"font-style:italic;\"> Sesamia spp </span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"font-style:italic;\"> Bemisia nigerensis </span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cassava mosaic disease is transmitted by the whitefly, <span style=\"font-style:italic;\"> Bemisia tabaci </span>. <span style=\"font-style:italic;\"> Bemisia nigerensis </span>is a species of whitefly, thus it is the correct answer. The whitefly acts as a vector, carrying the virus causing the disease from one plant to another.</div>", "topic": "CROP DISEASES"}, {"id": "objective>Agriculture>2013>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A serious pest of sweet potato whose larvae destroy the foliage is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">leaf miners</div>", "<div style=\"font-family:Cambria;font-size:17px;\">weevils mea</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mealy bugs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aphids</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Leaf miners are a serious pest of sweet potato. The larvae of leaf miners feed on the foliage of the sweet potato plant, causing significant damage. The other options listed are also pests, but they do not primarily target the foliage of the sweet potato plant.</div>", "topic": "CROP PESTS"}, {"id": "objective>Agriculture>2013>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The fertility of soils under forest is sustained mainly by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nutrient recycling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rodent activities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">being protected from direct rays of the sun</div>", "<div style=\"font-family:Cambria;font-size:17px;\">preventing raindrops from directly hitting the soil</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The fertility of soils under forest is sustained mainly by nutrient recycling. This is a process where nutrients from dead or decaying organisms are returned to the soil, which can then be used by other organisms. This process is crucial in forest ecosystems, where it helps to maintain soil fertility. The other options listed do not primarily contribute to soil fertility in forest ecosystems.</div>", "topic": "AGRICULTURAL ECOLOGY : ENVIRONMENTAL FACTORS"}, {"id": "objective>Agriculture>2013>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Mendelian law of segregation states that the characteristics which is hidden in an F1, reappears in F2 generation in a ratio of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1 : 2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 : 2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 : 3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3 : 2</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Mendelian law of segregation states that during gamete formation, the alleles for each gene segregate from each other so that each gamete carries only one allele for each gene. In the F2 generation, the hidden trait (recessive trait) reappears in a ratio of 1:3. This means for every one individual showing the recessive trait, there are three showing the dominant trait.</div>", "topic": "AGRICULTURAL GENETICS : FIRST AND SECOND LAWS OF MENDEL"}, {"id": "objective>Agriculture>2013>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The breed of sheep that can be found throughout Nigeria is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Yankasa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Uda</div>", "<div style=\"font-family:Cambria;font-size:17px;\">West Africa dwarf sheep</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Balami</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Yankasa sheep is the most common breed of sheep in Nigeria. It is found throughout the country but more common in the Northern part of the country. The other breeds mentioned are also found in Nigeria but not as widespread as the Yankasa.</div>", "topic": "FORMS AND CLASSIFICATION OF MAJOR FARM ANIMALS IN WEST AFRICA"}, {"id": "objective>Agriculture>2013>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A female cattle which has not had a calf or developed into the mature form of a cow is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">stag</div>", "<div style=\"font-family:Cambria;font-size:17px;\">yealing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heifer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vealers</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A heifer is a young female cow that has not yet had a calf. Once a heifer has a calf, she automatically becomes a cow. The term is used in the livestock industry to denote a female bovine that is yet to give birth to a calf or reach sexual maturity.</div>", "topic": "FORMS AND CLASSIFICATION OF MAJOR FARM ANIMALS IN WEST AFRICA"}, {"id": "objective>Agriculture>2013>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following farm animals is considered as monogastric?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Goat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pig</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cow</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sheep</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Monogastric animals are animals with single guts(stomach), i.e, they are not ruminant animals. Pigs are not ruminant animals,i.e, they are monogastric animals.</div>", "topic": "ANIMAL NUTRITION"}, {"id": "objective>Agriculture>2013>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The process of mating in poultry is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">servicing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">kidding</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tupping</div>", "<div style=\"font-family:Cambria;font-size:17px;\">treading</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In poultry, the process of mating is referred to as 'treading'. This term is specific to poultry and is used to describe the act of a rooster mounting a hen for the purpose of fertilization.</div>", "topic": "ANIMAL REPRODUCTION"}, {"id": "objective>Agriculture>2013>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In farm animals, a sign of heat includes</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">profuse salivation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">secretions from the vulva</div>", "<div style=\"font-family:Cambria;font-size:17px;\">difficulty in breathing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">continuous urination</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> The tell-tale sign that a female animal is in her heat period is secretion of fluids from the vulva(female genital opening).</div>", "topic": "ANIMAL HEALTH"}, {"id": "objective>Agriculture>2013>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The anti-sterility vitamin in livestocks nutrition is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">vitamin K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vitamin E</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vitamin C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vitamin B</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Vitamin E is known as the anti-sterility vitamin in livestock nutrition. It plays a crucial role in reproductive health and is essential for normal functioning of many enzymes and processes. Deficiency of Vitamin E can lead to sterility in animals.</div>", "topic": "ANIMAL NUTRITION"}, {"id": "objective>Agriculture>2013>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The relative humidity in an incubator is usually set at</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10% - 30%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40% - 60%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">70% - 80%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">90% - 100%.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The relative humidity in an incubator is usually set at 70% - 80%. This is because a high level of humidity is necessary for the proper development of the embryo. If the humidity is too low, the egg may lose too much water which can lead to the death of the embryo.</div>", "topic": "ANIMAL HEALTH"}, {"id": "objective>Agriculture>2013>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The causative organism of Avian influenza is a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bacterium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">virus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fungus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protozoan</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Avian influenza, also known as bird flu, is caused by a virus. The virus is highly contagious and can infect a wide range of birds including chickens, ducks, and turkeys. It can also spread to humans and other mammals.</div>", "topic": "ANIMAL HEALTH"}, {"id": "objective>Agriculture>2013>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The introduction of proper planktons species into the pond is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fertilization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">innoculation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stocking</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liming</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Innoculation is aimed at preventing animals from being infected by a particular disease. In a pond, this can be achieved by inroducing plankton species (mechanically)</div>", "topic": "FISHERIES AND WILDLIFE : FISH CULTURE SYSTEMS"}, {"id": "objective>Agriculture>2013>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Selection based on the performance of ancestors is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">family selection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pedigree selection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">progeny selection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">line selection</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Selection based on the performance of ancestors is referred to as 'pedigree selection'. Pedigree selection is a method of selection in which an individual is chosen from a population for reproduction based on the performance or phenotype of its ancestors.</div>", "topic": "AGRICULTURAL GENETICS : METHODS OF ANIMAL IMPROVEMENT"}, {"id": "objective>Agriculture>2013>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important of all the factors of production in crop farming is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">land</div>", "<div style=\"font-family:Cambria;font-size:17px;\">management.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Land is the most important of all factors of production in farm management as without a land, nothing can be achireved as far as farming is concern.</div>", "topic": "FACTORS OF AGRICULTURAL PRODUCTION : LAND"}, {"id": "objective>Agriculture>2013>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> From the curve above, at what point is it advisable for the farmer to stop further addition of input? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">At point III the farmer records maximum output, hence it is advisable that the farmer discontinue the addition of input.</div>", "topic": "FARM SURVEYING AND FARMSTEAD PLANNING : MEANING AND IMPORTANCE"}, {"id": "objective>Agriculture>2013>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Elastic demand is the type in which a change in price</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">brings about greater change in quantity of goods demanded</div>", "<div style=\"font-family:Cambria;font-size:17px;\">of a commodity leads to little or no change in demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">leads to equal change in commodity demanded</div>", "<div style=\"font-family:Cambria;font-size:17px;\">may not change the demand of quantity of commodity</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Elastic demand refers to a market situation where the quantity demanded of a good or service is sensitive to changes in price. In other words, a small change in price leads to a greater change in the quantity demanded. This is because consumers are more responsive to price changes in an elastic demand situation.</div>", "topic": "BASIC ECONOMIC PRINCIPLES : DEMAND AND SUPPLY"}, {"id": "objective>Agriculture>2013>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Farm labour is usually measured in terms of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">amount of wages paid to labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hours or days of work by labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">level of education of labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">type of work done by labour.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Farm labour is usually measured in terms of man-hours or man-days. This is the amount of work that can be done by one person in an hour or a day. It is a standard unit of measure in agriculture and other industries that helps to estimate the amount of work done or needed for a particular task. It does not necessarily correlate with the amount of wages paid, the level of education of the labour, or the type of work done.</div>", "topic": "FACTORS OF AGRICULTURAL PRODUCTION : LABOUR"}, {"id": "objective>Agriculture>2013>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A piece of information contained in payroll record of farms is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">date of employment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">income generated</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total credit</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pay-roll is a list of people employed by a company showing the amount of money to be paid to each of them. It usually includes the date of employement of workers.</div>", "topic": "FARM MANAGEMENT"}, {"id": "objective>Agriculture>2013>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Retailers may create artificial scarcity of goods by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">price hiking</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hoarding</div>", "<div style=\"font-family:Cambria;font-size:17px;\">under producing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">processing.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Retailers may create artificial scarcity of goods by hoarding. Hoarding involves keeping valuable items secretely in order to inflate their prices at some points.</div>", "topic": "MARKETING OF AGRICULTURAL PRODUCE"}, {"id": "objective>Agriculture>2013>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most effective method of disseminating information among farmers is through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">individual method</div>", "<div style=\"font-family:Cambria;font-size:17px;\">group method</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mass method</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cooperative method</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most effective method of disseminating information among farmers is through the group method. The group method involves gathering farmers in a group and providing them with the necessary information. This method is effective because it allows for interaction, discussion, and clarification of points. It also allows for the sharing of experiences and ideas among the farmers, which can lead to better understanding and application of the information.</div>", "topic": "AGRICULTURAL EXTENSION : EXTENSION METHODS"}, {"id": "objective>Agriculture>2013>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In surveying, the instrument used to measure horizontal, vertical angles and planes is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gunters chain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prismatic compass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ranging poles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">theodolite</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In surveying, the instrument used to measure horizontal, vertical angles and planes is the theodolite. A theodolite is a precision instrument for measuring angles in the horizontal and vertical planes. It is used mainly for surveying applications, and is also used extensively for building and infrastructure construction, and some specialized applications such as meteorology and rocket launching.</div>", "topic": "FARM SURVEYING AND FARMSTEAD PLANNING : SURVEYING EQUIPMENT"}, {"id": "objective>Agriculture>2013>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> During which of the following plant propagation methods is the tool represented used?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Seed planting.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Seedling transplant.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Budding</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Layering</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Budding is a process of artificial propagation. It involves the formation of an outgrowth (bud) from a parent plant which eventually leads to the sprouting of a mature plant with similar features as the parent plant.</div>", "topic": "PLANT PROPAGATION METHODS"}, {"id": "objective>Agriculture>2013>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The part labeled I is made of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wood</div>", "<div style=\"font-family:Cambria;font-size:17px;\">iron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aluminium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lead</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The tip/metallic part of a budding or tapping knife is made of steel or iron, therefore the answer to the question is \"iron\".</div>", "topic": "FARM MACHINERY AND IMPLEMENTS : TYPES"}, {"id": "objective>Agriculture>2013>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following routine maintenance in a tractor is necessary on daily basis?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Draining of the gear box oil.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Removing and cleaning of engines air filter.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Replacing of the fuel filter element.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Checking of the oil level in the engine</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Checking of the oil level in the engine is a maintenance procedure that should be carried out on a daily basis.</div>", "topic": "FARM MACHINERY AND IMPLEMENTS : USES AND MAINTENANCE"}, {"id": "objective>Agriculture>2013>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The type of energy obtain from the sun is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hydro energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">solar energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">thermal energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wind energy</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The type of energy obtained from the sun is solar energy. Solar energy is the energy that is produced by the sun's light and heat. It is a renewable source of energy that can be harnessed using various technologies such as solar panels to generate electricity, heat water, and heat buildings. The other options, hydro energy, thermal energy, and wind energy, are also forms of renewable energy, but they are not directly obtained from the sun.</div>", "topic": "ENVIRONMENTAL FACTORS"}, {"id": "objective>Agriculture>2013>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The storage facility that is not suitable for grains is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">silos</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rumbus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">barns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sacs</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rumbus is not a suitable storage facility for grains. A rumbus is not a recognized term in the context of grain storage. Silos, barns, and sacs, on the other hand, are commonly used for storing grains. Silos are tall, cylindrical structures that are used for storing bulk materials, including grains. Barns are large farm buildings that are used for storing farm equipment and produce, including grains. Sacs are bags that are used for storing small quantities of grains.</div>", "topic": "CROP HUSBANDRY : STORAGE FACILITIES"}, {"id": "objective>Agriculture>2013>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In biotechnology, propagation is mainly by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">grafting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aerial layering</div>", "<div style=\"font-family:Cambria;font-size:17px;\">binary fission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cell culture</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In biotechnology, propagation is mainly by cell culture. This is because cell culture allows for the growth of cells under controlled conditions, usually outside their natural environment. This method is used in biotechnology because it allows for the production of genetically identical cells, which is important for maintaining the characteristics of the original organism.</div>", "topic": "PLANT PROPAGATION METHODS"}, {"id": "objective>Agriculture>2013>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The desktop computer used for data management in agri-business is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an analog computer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a super computer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a hybrid computer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a mainframe computer</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A mainframe computer can be used for data management in agric-business. Mainframe computers are powerful systems capable of handling large volumes of data and supporting numerous simultaneous transactions, making them suitable for the extensive data processing and management needs in agri-business. Hybrid computers, while useful in certain specialized applications that require both analog and digital data processing, do not typically match the data management capabilities of mainframe computers.</div>", "topic": "APPLICATION OF ICT IN AGRICULTURE : USES OF COMPUTERS IN AGRICULTURE"}, {"id": "objective>Agriculture>2013>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A hypothesis can be described as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">predictive statement relating to experimental variables</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tea postulate of general acceptance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a research reasoning based on an accurate statement about the population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a postulate based on experimental samples</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A hypothesis is a reasonable explanation to a particular observation. We may also describe it as a predictive statement relating to expermental variables.</div>", "topic": "AGRICULTURAL EXTENSION : EXTENSION METHODS"}];
